const raw = $input.first().json;
const d = raw.body || raw.query || raw;
d.runtime_mode = d.runtime_mode || "MOCK";
d.correlation_id = d.correlation_id || ("INT-" + Date.now());
d.request_id = d.request_id || ("REQ-" + Math.random().toString(36).substr(2,8).toUpperCase());
d.user = d.user || {id:"system",name:"Auto",role:"user",department:"interno"};
d.payload = d.payload || {};
d.metadata = d.metadata || {};
const msg = (d.message || "").toLowerCase();
if (!d.action) {
  if (/certificado|vencimento|\bcertif/.test(msg)) d.action = "consult_certificate";
  else if (/consultar.*(computador|ativo|equipamento)|ativo de|equipamento de/.test(msg)) d.action = "consult_asset";
  else if (/senha|acesso|permissao|permiss.o|login|reset/.test(msg)) d.action = "password_access_request";
  else if (/onboarding|novo funcion.rio|novo colaborador/.test(msg)) d.action = "onboarding_request";
  else if (/resumo|chamados de hoje|daily summary/.test(msg)) d.action = "daily_summary";
  else if (/\bpc\b|computador|rede|internet|impressora|sistema|\berro\b|software/.test(msg)) d.action = "create_ticket";
  else d.action = "intake";
}
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const action = d.action || "intake";
const msg = d.message || "";
if (action === "daily_summary") { d._validation = {valid:true,missing:[]}; d._needs_info = false; return [{json:d}]; }
const missing = [];
const hasMsg = msg.length > 5;
const hasId = pl.ticket_id || pl.asset_id || pl.computer_name || pl.target_user_id;
if (action === "close_ticket_request" && !pl.ticket_id) missing.push("ticket_id");
if (action === "consult_asset" && !hasId && !hasMsg) missing.push("asset_id_or_computer_name_or_user");
if (!hasMsg && !hasId) missing.push("message_or_payload_id");
d._validation = {valid: missing.length === 0, missing};
d._needs_info = missing.length > 0;
return [{json: d}];

const d = $input.first().json;
d._status = "needs_info";
const miss = (d._validation ? d._validation.missing : null) || ["message_or_payload"];
d._clarification = {questions: miss.map(function(m){return "Informar " + m + " para continuar";}), missing: miss};
return [{json: d}];

const d = $input.first().json;
const msg = (d.message || "").toLowerCase();
const pl = d.payload || {};
let category = pl.category || "other";
let urgency = pl.urgency || "medium";
if (category === "other" || !pl.category) {
  if (/impressora|printer/.test(msg)) category = "printer";
  else if (/\brede\b|internet|wifi|wi-fi|network/.test(msg)) category = "network";
  else if (/senha|acesso|permissao|login|reset|password/.test(msg)) category = "password";
  else if (/certificado|certif/.test(msg)) category = "certificate";
  else if (/\bpc\b|computador|monitor|teclado|mouse|hardware/.test(msg)) category = "hardware";
  else if (/software|programa|aplicativo|instalar|install/.test(msg)) category = "software";
  else if (/email|e-mail|correio/.test(msg)) category = "email";
  else if (/portal|sistema do portal/.test(msg)) category = "portal_system";
  else if (/producao|produção|erp|sistema da prod/.test(msg)) category = "erp_system";
  else if (/onboarding|novo funcion/.test(msg)) category = "onboarding";
  else if (/ativo|equipamento|asset/.test(msg)) category = "asset";
}
if (!pl.urgency) {
  if (/parado|sem internet em todo|sistema parado|credencial vaz|acesso indevido|perda de dados/.test(msg)) urgency = "critical";
  else if (/urgente|nao consigo trabalhar|critico|email parado|setor parado/.test(msg)) urgency = "high";
}
const secSensitive = ["password","access","account"].includes(category) || /senha|acesso|credencial/.test(msg);
const needsHuman = ["critical","high"].includes(urgency) || secSensitive;
d._classification = {
  category: category, urgency: urgency,
  needs_human: needsHuman, security_sensitive: secSensitive,
  title: "Chamado " + category.toUpperCase() + " - " + (d.message || "Sem titulo").substring(0, 60),
  description: d.message || pl.notes || ""
};
return [{json: d}];

const d = $input.first().json;
const cls = d._classification || {};
const msg = (d.message || "").toLowerCase();
const urgency = cls.urgency || "medium";
const category = cls.category || "other";
let risk = "low";
if (/credencial vaz|acesso indevido|perda de dados|breach/.test(msg)) { risk = "critical"; }
else if (cls.security_sensitive || urgency === "critical" || /setor parado|sistema parado/.test(msg)) { risk = "high"; }
else if (urgency === "high" || ["certificate","password","access","account","erp_system"].includes(category)) { risk = "high"; }
else if (urgency === "medium" || ["network","email","portal_system","hardware"].includes(category)) { risk = "medium"; }
d._risk_level = risk;
d._requires_approval = ["password_access_request","onboarding_request"].includes(d.action);
d._policy = {
  create_ticket_allowed: true, classify_ticket_allowed: true,
  suggest_solution_allowed: true, consult_asset_allowed: true,
  consult_cert_allowed: true, notify_allowed: true,
  reset_password_blocked: true, change_access_blocked: true,
  install_software_blocked: true, delete_user_blocked: true,
  security_sensitive: cls.security_sensitive || false
};
return [{json: d}];

