    {certificate_id:"CERT-002",name:"Certificado INMETRO EX",owner:"Qualidade",expires_at:expPast,days_to_expire:-5,status:"expired",recommended_action:"Renovacao urgente - produto bloqueado"},
    {certificate_id:"CERT-003",name:"Assinatura Digital NF-e",owner:"Financeiro",expires_at:"2025-12-31",days_to_expire:220,status:"valid",recommended_action:"Monitorar"}
  ];
  alerts = d._certificates.filter(function(c){return c.status !== "valid";});
  d._cert_alerts = alerts;
  if (alerts.length > 0) { d._risk_level = "high"; d._notification_prepared = true; }
}
d._status = alerts.length > 0 ? "certificate_alert" : "asset_found";
return [{json: d}];

